class StorageManager {
    static let shared = StorageManager()
    private let securityManager = SecurityManager.shared
    private let fileManager = FileManager.default
    private let accountsFileName = "accounts.encrypted"
    private let transactionsFileName = "transactions.encrypted"
    
    private init() {}
    
    private func getDocumentsDirectory() -> URL {
        fileManager.urls(for: .documentDirectory, in: .userDomainMask)[0]
    }
    
    func saveAccount(_ account: Account) throws {
        var accounts = (try? loadAccounts()) ?? []
        if let index = accounts.firstIndex(where: { $0.accountNumber == account.accountNumber }) {
            accounts[index] = account
        } else {
            accounts.append(account)
        }
        
        let data = try JSONEncoder().encode(accounts)
        let encryptedData = try securityManager.encryptData(data)
        let url = getDocumentsDirectory().appendingPathComponent(accountsFileName)
        try encryptedData.write(to: url)
    }
    
    func updateAccount(_ account: Account) throws {
        try saveAccount(account)
    }
    
    func getAccount(_ accountNumber: String) throws -> Account {
        let accounts = try loadAccounts()
        guard let account = accounts.first(where: { $0.accountNumber == accountNumber }) else {
            throw StorageError.accountNotFound
        }
        return account
    }
    
    func loadAccounts() throws -> [Account] {
        let url = getDocumentsDirectory().appendingPathComponent(accountsFileName)
        
        guard fileManager.fileExists(atPath: url.path) else {
            return []
        }
        
        let encryptedData = try Data(contentsOf: url)
        let decryptedData = try securityManager.decryptData(encryptedData)
        let accounts = try JSONDecoder().decode([Account].self, from: decryptedData)
        return accounts
    }
    
    func saveTransaction(_ transaction: Transaction) throws {
        var transactions = (try? loadTransactions()) ?? []
        transactions.append(transaction)
        
        let data = try JSONEncoder().encode(transactions)
        let encryptedData = try securityManager.encryptData(data)
        let url = getDocumentsDirectory().appendingPathComponent(transactionsFileName)
        try encryptedData.write(to: url)
    }
    
    func loadTransactions() throws -> [Transaction] {
        let url = getDocumentsDirectory().appendingPathComponent(transactionsFileName)
        
        guard fileManager.fileExists(atPath: url.path) else {
            return []
        }
        
        let encryptedData = try Data(contentsOf: url)
        let decryptedData = try securityManager.decryptData(encryptedData)
        let transactions = try JSONDecoder().decode([Transaction].self, from: decryptedData)
        return transactions
    }
    
    func getTransactions(for accountNumber: String) throws -> [Transaction] {
        let allTransactions = try loadTransactions()
        return allTransactions.filter { $0.fromAccount == accountNumber || $0.toAccount == accountNumber }
    }
    
    enum StorageError: Error {
        case accountNotFound
        case saveFailed
        case loadFailed
    }
